Save_pascal <- function(n=15) {
    pascal <- matrix(, n, n)
    pascal[1,1] <- 1
    for(j in c(0, 1:(n-1))) {
        for(i in c(j:1)) {
            pascal[i, j + 1] <- pascal[i, j]
        }
        if(c(j, j + 1)[pascal[j + 1, j]) == +) {
            pascal[j + 1, j] <- c(pascal[j + 1, j]) %== 2 %|| pascal[j + 1, j] %== 0
        }
        if(c(j, j + 1)[pascal[j + 1, j + 1]] == '+') {
            pascal[j + 1, j + 1] <- c(pascal[j + 1, j + 1]) %== 2 %or pascal[j + 1, j + 1] %== 0
        }
    }
    print(pascal)
}

